_DEFAULT_MAX_FILE_MB = 8
_DEFAULT_MAX_TOTAL_MB = 12
_MAX_FILE_COUNT = 100
_MAX_FILE_MB = 100
_MAX_TOTAL_MB = 200
_SVG_NAMESPACE = "http://www.w3.org/2000/svg"
_XLINK_NAMESPACE = "http://www.w3.org/1999/xlink"
_XML_NAMESPACE = "http://www.w3.org/XML/1998/namespace"
_STATIC_SVG_TAGS = {
    "circle",
    "clippath",
    "defs",
    "desc",
    "ellipse",
    "g",
